import{_ as t,o as l,c as r,ag as e}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"AI 发展简史：从图灵测试到大模型时代","description":"一篇文章带你了解人工智能从诞生到爆发的完整历程","frontmatter":{"title":"AI 发展简史：从图灵测试到大模型时代","date":"2026-04-01T00:00:00.000Z","description":"一篇文章带你了解人工智能从诞生到爆发的完整历程","tags":["AI","人工智能，历史，大模型"]},"headers":[],"relativePath":"posts/ai-history.md","filePath":"posts/ai-history.md"}'),o={name:"posts/ai-history.md"};function i(n,a,h,s,d,u){return l(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="ai-发展简史-从图灵测试到大模型时代-🤖" tabindex="-1">AI 发展简史：从图灵测试到大模型时代 🤖 <a class="header-anchor" href="#ai-发展简史-从图灵测试到大模型时代-🤖" aria-label="Permalink to &quot;AI 发展简史：从图灵测试到大模型时代 🤖&quot;">​</a></h1><blockquote><p>&quot;人工智能是计算机科学中最迷人也最具挑战性的领域之一。&quot;</p></blockquote><p>人工智能（AI）的发展可谓跌宕起伏，经历了多次高潮与低谷。今天，让我们一起回顾这段激动人心的历史。</p><hr><h2 id="📜-第一章-萌芽期-1940s-1950s" tabindex="-1">📜 第一章：萌芽期（1940s-1950s） <a class="header-anchor" href="#📜-第一章-萌芽期-1940s-1950s" aria-label="Permalink to &quot;📜 第一章：萌芽期（1940s-1950s）&quot;">​</a></h2><h3 id="_1943-年-神经网络的理论奠基" tabindex="-1">1943 年：神经网络的理论奠基 <a class="header-anchor" href="#_1943-年-神经网络的理论奠基" aria-label="Permalink to &quot;1943 年：神经网络的理论奠基&quot;">​</a></h3><p>美国神经科学家<strong>麦卡洛克</strong>（Warren McCulloch）和数学家<strong>皮茨</strong>（Walter Pitts）提出了第一个人工神经元模型——<strong>M-P 模型</strong>，为后来的神经网络研究奠定了理论基础。</p><h3 id="_1950-年-图灵测试诞生" tabindex="-1">1950 年：图灵测试诞生 <a class="header-anchor" href="#_1950-年-图灵测试诞生" aria-label="Permalink to &quot;1950 年：图灵测试诞生&quot;">​</a></h3><p>英国数学家<strong>艾伦·图灵</strong>（Alan Turing）发表了划时代的论文《计算机器与智能》，提出了著名的<strong>图灵测试</strong>：</p><blockquote><p>&quot;如果一台机器能够与人类对话而不被辨别出其机器身份，那么这台机器就具有智能。&quot;</p></blockquote><p>这标志着人工智能概念的正式诞生！</p><h3 id="_1956-年-达特茅斯会议——ai-正式诞生" tabindex="-1">1956 年：达特茅斯会议——AI 正式诞生 <a class="header-anchor" href="#_1956-年-达特茅斯会议——ai-正式诞生" aria-label="Permalink to &quot;1956 年：达特茅斯会议——AI 正式诞生&quot;">​</a></h3><p>在<strong>约翰·麦卡锡</strong>（John McCarthy）的组织下，达特茅斯学院召开了为期两个月的研讨会，首次正式提出&quot;<strong>Artificial Intelligence</strong>&quot;（人工智能）这一术语。</p><p>参会的大佬包括：</p><ul><li>马文·明斯基（Marvin Minsky）</li><li>克劳德·香农（Claude Shannon）</li><li>艾伦·纽厄尔（Allen Newell）</li><li>赫伯特·西蒙（Herbert Simon）</li></ul><p>这次会议被公认为<strong>人工智能诞生的标志</strong>。</p><hr><h2 id="📈-第二章-第一次高潮-1956-1974" tabindex="-1">📈 第二章：第一次高潮（1956-1974） <a class="header-anchor" href="#📈-第二章-第一次高潮-1956-1974" aria-label="Permalink to &quot;📈 第二章：第一次高潮（1956-1974）&quot;">​</a></h2><h3 id="早期成就" tabindex="-1">早期成就 <a class="header-anchor" href="#早期成就" aria-label="Permalink to &quot;早期成就&quot;">​</a></h3><ul><li><strong>1957 年</strong>：弗兰克·罗森布拉特发明了<strong>感知机</strong>（Perceptron），这是第一个可以学习的神经网络模型</li><li><strong>1959 年</strong>：阿瑟·塞缪尔开发了第一个<strong>跳棋程序</strong>，能够自我学习并击败人类选手</li><li><strong>1964 年</strong>：MIT 的<strong>STUDENT</strong>程序可以解代数应用题</li><li><strong>1966 年</strong>：ELIZA 聊天机器人诞生，能模拟心理治疗师与人对话</li></ul><h3 id="政府的巨额投入" tabindex="-1">政府的巨额投入 <a class="header-anchor" href="#政府的巨额投入" aria-label="Permalink to &quot;政府的巨额投入&quot;">​</a></h3><p>这一时期，美国国防部高级研究计划局（DARPA）投入了大量资金支持 AI 研究，学术界对 AI 的前景极度乐观。</p><blockquote><p>&quot;机器将在二十年内能够完成任何人能做的工作。&quot; —— 赫伯特·西蒙，1965 年</p></blockquote><hr><h2 id="❄️-第三章-第一次-ai-寒冬-1974-1980" tabindex="-1">❄️ 第三章：第一次 AI 寒冬（1974-1980） <a class="header-anchor" href="#❄️-第三章-第一次-ai-寒冬-1974-1980" aria-label="Permalink to &quot;❄️ 第三章：第一次 AI 寒冬（1974-1980）&quot;">​</a></h2><h3 id="理想与现实的差距" tabindex="-1">理想与现实的差距 <a class="header-anchor" href="#理想与现实的差距" aria-label="Permalink to &quot;理想与现实的差距&quot;">​</a></h3><p>尽管早期取得了一些成功，但研究者很快发现：</p><ul><li>计算能力严重不足</li><li>数据极其匮乏</li><li>很多看似简单的问题（如视觉识别、自然语言理解）实际上异常困难</li></ul><h3 id="批评与质疑" tabindex="-1">批评与质疑 <a class="header-anchor" href="#批评与质疑" aria-label="Permalink to &quot;批评与质疑&quot;">​</a></h3><p>1969 年，明斯基和佩珀特出版了《感知机》一书，从数学上证明了单层感知机的局限性，导致神经网络研究陷入低谷。</p><p>政府资助大幅削减，AI 研究进入第一个&quot;寒冬&quot;。</p><hr><h2 id="🌸-第四章-复兴期-1980-1987" tabindex="-1">🌸 第四章：复兴期（1980-1987） <a class="header-anchor" href="#🌸-第四章-复兴期-1980-1987" aria-label="Permalink to &quot;🌸 第四章：复兴期（1980-1987）&quot;">​</a></h2><h3 id="专家系统的崛起" tabindex="-1">专家系统的崛起 <a class="header-anchor" href="#专家系统的崛起" aria-label="Permalink to &quot;专家系统的崛起&quot;">​</a></h3><p><strong>专家系统</strong>（Expert Systems）成为主流，这类系统通过存储大量领域知识和规则来模拟人类专家的决策能力。</p><p>著名案例：</p><ul><li><strong>MYCIN</strong>：用于诊断血液感染疾病</li><li><strong>DENDRAL</strong>：用于分析化学物质结构</li><li><strong>XCON</strong>：帮助 DEC 公司配置计算机系统，每年节省数百万美元</li></ul><h3 id="日本-第五代计算机-计划" tabindex="-1">日本&quot;第五代计算机&quot;计划 <a class="header-anchor" href="#日本-第五代计算机-计划" aria-label="Permalink to &quot;日本&quot;第五代计算机&quot;计划&quot;">​</a></h3><p>1982 年，日本启动雄心勃勃的&quot;第五代计算机&quot;项目，目标是制造能理解自然语言、进行逻辑推理的智能计算机。这引发了全球 AI 竞赛。</p><h3 id="神经网络的复兴" tabindex="-1">神经网络的复兴 <a class="header-anchor" href="#神经网络的复兴" aria-label="Permalink to &quot;神经网络的复兴&quot;">​</a></h3><p>1986 年，<strong>反向传播算法</strong>（Backpropagation）被重新发现，使得多层神经网络的训练成为可能，深度学习迎来第一次曙光。</p><hr><h2 id="❄️-第五章-第二次-ai-寒冬-1987-1993" tabindex="-1">❄️ 第五章：第二次 AI 寒冬（1987-1993） <a class="header-anchor" href="#❄️-第五章-第二次-ai-寒冬-1987-1993" aria-label="Permalink to &quot;❄️ 第五章：第二次 AI 寒冬（1987-1993）&quot;">​</a></h2><h3 id="专家系统的局限" tabindex="-1">专家系统的局限 <a class="header-anchor" href="#专家系统的局限" aria-label="Permalink to &quot;专家系统的局限&quot;">​</a></h3><ul><li>维护成本高昂</li><li>难以处理不确定性</li><li>无法学习新知识</li><li>缺乏常识推理能力</li></ul><h3 id="市场崩溃" tabindex="-1">市场崩溃 <a class="header-anchor" href="#市场崩溃" aria-label="Permalink to &quot;市场崩溃&quot;">​</a></h3><p>随着专家系统商业应用的失败，AI 公司纷纷倒闭，投资再次撤离。</p><p>日本&quot;第五代计算机&quot;项目也未能实现目标，于 1992 年宣告结束。</p><hr><h2 id="🚀-第六章-稳步发展期-1993-2010" tabindex="-1">🚀 第六章：稳步发展期（1993-2010） <a class="header-anchor" href="#🚀-第六章-稳步发展期-1993-2010" aria-label="Permalink to &quot;🚀 第六章：稳步发展期（1993-2010）&quot;">​</a></h2><h3 id="机器学习的兴起" tabindex="-1">机器学习的兴起 <a class="header-anchor" href="#机器学习的兴起" aria-label="Permalink to &quot;机器学习的兴起&quot;">​</a></h3><p>研究者开始转向更务实的方法：<strong>机器学习</strong>（Machine Learning）。</p><p>关键突破：</p><ul><li><strong>1997 年</strong>：IBM 的<strong>深蓝</strong>（Deep Blue）击败国际象棋世界冠军卡斯帕罗夫</li><li><strong>2006 年</strong>：杰弗里·辛顿提出<strong>深度学习</strong>（Deep Learning）概念</li><li><strong>2009 年</strong>：ImageNet 数据集发布，为计算机视觉研究提供大规模训练数据</li></ul><h3 id="统计方法的胜利" tabindex="-1">统计方法的胜利 <a class="header-anchor" href="#统计方法的胜利" aria-label="Permalink to &quot;统计方法的胜利&quot;">​</a></h3><p>基于统计的机器学习方法在语音识别、机器翻译等领域取得显著进展，AI 开始真正落地应用。</p><hr><h2 id="🔥-第七章-深度学习革命-2012-2020" tabindex="-1">🔥 第七章：深度学习革命（2012-2020） <a class="header-anchor" href="#🔥-第七章-深度学习革命-2012-2020" aria-label="Permalink to &quot;🔥 第七章：深度学习革命（2012-2020）&quot;">​</a></h2><h3 id="_2012-年-alexnet-引爆深度学习" tabindex="-1">2012 年：AlexNet 引爆深度学习 <a class="header-anchor" href="#_2012-年-alexnet-引爆深度学习" aria-label="Permalink to &quot;2012 年：AlexNet 引爆深度学习&quot;">​</a></h3><p>在 ImageNet 图像识别竞赛中，<strong>AlexNet</strong>以压倒性优势夺冠，错误率从 26% 降至 15.3%。这标志着深度学习时代的正式到来！</p><h3 id="关键里程碑" tabindex="-1">关键里程碑 <a class="header-anchor" href="#关键里程碑" aria-label="Permalink to &quot;关键里程碑&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>事件</th><th>意义</th></tr></thead><tbody><tr><td>2014</td><td>GAN（生成对抗网络）诞生</td><td>开启了 AI 生成内容的新纪元</td></tr><tr><td>2015</td><td>ResNet（残差网络）</td><td>解决了深层网络训练难题</td></tr><tr><td>2016</td><td>AlphaGo 击败李世石</td><td>AI 在围棋领域超越人类</td></tr><tr><td>2017</td><td>Transformer 架构提出</td><td>彻底改变了 NLP 领域</td></tr><tr><td>2018</td><td>BERT 发布</td><td>预训练模型成为主流</td></tr><tr><td>2020</td><td>GPT-3 问世</td><td>大模型时代开启</td></tr></tbody></table><h3 id="alphago-时刻" tabindex="-1">AlphaGo 时刻 <a class="header-anchor" href="#alphago-时刻" aria-label="Permalink to &quot;AlphaGo 时刻&quot;">​</a></h3><p>2016 年 3 月，谷歌 DeepMind 的<strong>AlphaGo</strong>以 4:1 击败围棋世界冠军李世石，震惊世界。围棋曾被认为是 AI 最难攻克的领域之一，因为它的复杂度远超国际象棋。</p><blockquote><p>&quot;AlphaGo 的每一步都充满创造力，它下出了人类从未想过的棋。&quot; —— 李世石</p></blockquote><hr><h2 id="💥-第八章-大模型时代-2020-至今" tabindex="-1">💥 第八章：大模型时代（2020-至今） <a class="header-anchor" href="#💥-第八章-大模型时代-2020-至今" aria-label="Permalink to &quot;💥 第八章：大模型时代（2020-至今）&quot;">​</a></h2><h3 id="gpt-系列的进化" tabindex="-1">GPT 系列的进化 <a class="header-anchor" href="#gpt-系列的进化" aria-label="Permalink to &quot;GPT 系列的进化&quot;">​</a></h3><h4 id="gpt-3-2020" tabindex="-1">GPT-3（2020） <a class="header-anchor" href="#gpt-3-2020" aria-label="Permalink to &quot;GPT-3（2020）&quot;">​</a></h4><ul><li>参数量：1750 亿</li><li>能力：文本生成、问答、翻译、代码编写</li><li>影响：展示了<strong>涌现能力</strong>——模型规模达到一定程度后，突然获得意想不到的能力</li></ul><h4 id="chatgpt-2022" tabindex="-1">ChatGPT（2022） <a class="header-anchor" href="#chatgpt-2022" aria-label="Permalink to &quot;ChatGPT（2022）&quot;">​</a></h4><ul><li>基于 GPT-3.5，加入人类反馈强化学习（RLHF）</li><li>用户数：2 个月破亿，史上增长最快的消费级应用</li><li>影响：引发全球对 AI 的关注和投资热潮</li></ul><h4 id="gpt-4-2023" tabindex="-1">GPT-4（2023） <a class="header-anchor" href="#gpt-4-2023" aria-label="Permalink to &quot;GPT-4（2023）&quot;">​</a></h4><ul><li>多模态能力（图文理解）</li><li>更强的推理和代码能力</li><li>在多项专业考试中达到人类顶尖水平</li></ul><h3 id="百花齐放" tabindex="-1">百花齐放 <a class="header-anchor" href="#百花齐放" aria-label="Permalink to &quot;百花齐放&quot;">​</a></h3><ul><li><strong>Google</strong>: PaLM、Gemini</li><li><strong>Meta</strong>: LLaMA 系列（开源）</li><li><strong>Anthropic</strong>: Claude 系列</li><li><strong>中国</strong>: 文心一言、通义千问、Kimi、DeepSeek 等</li></ul><h3 id="_2025-2026-ai-agent-时代" tabindex="-1">2025-2026：AI Agent 时代 <a class="header-anchor" href="#_2025-2026-ai-agent-时代" aria-label="Permalink to &quot;2025-2026：AI Agent 时代&quot;">​</a></h3><p>AI 不再只是回答问题，而是能够：</p><ul><li>自主规划任务</li><li>使用工具（浏览器、代码执行、API 调用）</li><li>多步骤推理和长期记忆</li><li>与其他 AI 协作</li></ul><hr><h2 id="🎯-第九章-关键技术突破解析" tabindex="-1">🎯 第九章：关键技术突破解析 <a class="header-anchor" href="#🎯-第九章-关键技术突破解析" aria-label="Permalink to &quot;🎯 第九章：关键技术突破解析&quot;">​</a></h2><h3 id="_1-transformer-架构" tabindex="-1">1. Transformer 架构 <a class="header-anchor" href="#_1-transformer-架构" aria-label="Permalink to &quot;1. Transformer 架构&quot;">​</a></h3><p>2017 年谷歌提出的 Transformer 彻底改变了 NLP：</p><ul><li><strong>自注意力机制</strong>：让模型能够关注输入的不同部分</li><li><strong>并行计算</strong>：大幅提升训练效率</li><li><strong>可扩展性</strong>：模型可以做得越来越大</li></ul><h3 id="_2-预训练-微调范式" tabindex="-1">2. 预训练 + 微调范式 <a class="header-anchor" href="#_2-预训练-微调范式" aria-label="Permalink to &quot;2. 预训练 + 微调范式&quot;">​</a></h3><ul><li>先在海量数据上预训练</li><li>再用少量标注数据微调</li><li>大幅降低了特定任务的门槛</li></ul><h3 id="_3-人类反馈强化学习-rlhf" tabindex="-1">3. 人类反馈强化学习（RLHF） <a class="header-anchor" href="#_3-人类反馈强化学习-rlhf" aria-label="Permalink to &quot;3. 人类反馈强化学习（RLHF）&quot;">​</a></h3><p>让人类给 AI 的回答打分，训练 AI 更符合人类偏好，使对话更自然、更有用。</p><hr><h2 id="🔮-第十章-未来展望" tabindex="-1">🔮 第十章：未来展望 <a class="header-anchor" href="#🔮-第十章-未来展望" aria-label="Permalink to &quot;🔮 第十章：未来展望&quot;">​</a></h2><h3 id="短期趋势-1-3-年" tabindex="-1">短期趋势（1-3 年） <a class="header-anchor" href="#短期趋势-1-3-年" aria-label="Permalink to &quot;短期趋势（1-3 年）&quot;">​</a></h3><ul><li>✅ 多模态 AI 成为标配（文字、图片、音频、视频）</li><li>✅ AI Agent 普及，能自主完成复杂任务</li><li>✅ 垂直领域专业化模型爆发</li><li>✅ AI 编程助手成为开发者标配</li></ul><h3 id="中期趋势-3-10-年" tabindex="-1">中期趋势（3-10 年） <a class="header-anchor" href="#中期趋势-3-10-年" aria-label="Permalink to &quot;中期趋势（3-10 年）&quot;">​</a></h3><ul><li>🤔 通用人工智能（AGI）的探索</li><li>🤔 AI 与脑科学的交叉融合</li><li>🤔 量子计算对 AI 的赋能</li><li>🤔 AI 伦理和治理框架完善</li></ul><h3 id="长期思考" tabindex="-1">长期思考 <a class="header-anchor" href="#长期思考" aria-label="Permalink to &quot;长期思考&quot;">​</a></h3><blockquote><p>&quot;AI 会是人类最后需要发明的东西吗？&quot;</p></blockquote><p>如果 AGI 实现，人类社会将面临前所未有的变革：</p><ul><li>工作形态的重塑</li><li>教育体系的革新</li><li>社会结构的调整</li><li>人类自我认知的挑战</li></ul><hr><h2 id="💡-结语-站在历史的肩膀上" tabindex="-1">💡 结语：站在历史的肩膀上 <a class="header-anchor" href="#💡-结语-站在历史的肩膀上" aria-label="Permalink to &quot;💡 结语：站在历史的肩膀上&quot;">​</a></h2><p>回顾 AI 发展的 70 多年历程，我们看到：</p><ul><li><strong>坚持</strong>：经历两次寒冬仍不放弃的研究者</li><li><strong>创新</strong>：从符号主义到连接主义的范式转变</li><li><strong>合作</strong>：全球科学家的开放共享精神</li><li><strong>务实</strong>：从追求通用智能到解决具体问题</li></ul><p>正如深度学习先驱杰弗里·辛顿所说：</p><blockquote><p>&quot;我坚信，我们正处于一场革命的开端，这场革命将彻底改变人类文明。&quot;</p></blockquote><p>作为这个时代的见证者和参与者，我们每个人都在书写 AI 历史的下一页。</p><hr><p><strong>参考文献与延伸阅读</strong></p><ol><li>《人工智能：一种现代方法》- Stuart Russell &amp; Peter Norvig</li><li>《深度学习》- Ian Goodfellow, Yoshua Bengio, Aaron Courville</li><li>《生命 3.0》- Max Tegmark</li><li><a href="https://openai.com" target="_blank" rel="noreferrer">OpenAI 官网</a></li><li><a href="https://deepmind.google" target="_blank" rel="noreferrer">DeepMind 官网</a></li></ol><hr><p><em>本文首发于南风的博客，欢迎转载分享～</em> ❤️</p>',110)])])}const q=t(o,[["render",i]]);export{p as __pageData,q as default};
